html+='<h3>当前产品已上传/已配对配光曲线</h3><div class="image-grid">';
if(!rows.length) html+='<div class="empty">当前产品暂无配光曲线图片。请先从公共配光曲线库搜索并配对。</div>';
rows.forEach(c=>{let u=c.url||c.image||'', title=c.label||c.file_title||c.original_name||'配光曲线';html+='<div class="image-tile">'+(u?'<img src="'+esc(u)+'" onclick="openImagePreview(\''+esc(u)+'\',\'配光曲线\')">':'<div class="empty">非图片文件</div>')+'<b>'+esc(title)+'</b><small>'+esc(c.source==='upload'?'手动上传/公共库配对':'缓存/官网')+'</small><div class="item-actions">'+(u?'<button onclick="openImagePreview(\''+esc(u)+'\',\'配光曲线\')">预览</button>':'')+(c.id?'<a class="btn" target="_blank" href="datasheet_api.php?action=download_file&id='+encodeURIComponent(c.id)+'">下载</a>':'')+(c.id?'<button onclick="editLibraryFile('+c.id+',\''+esc(title)+'\',\'配光曲线\',\'\')">修改</button>':'')+(state.perms.delete_file&&c.id?'<button class="danger" onclick="deleteFile('+c.id+',\'curves\')">删除</button>':'')+'</div></div>'});
html+='</div><h3>从公共配光曲线库搜索并确认配对</h3><div class="form-grid"><div class="field span3"><label>模糊查找</label><input id="curveKw" placeholder="型号 / 角度 / 文件名" onkeydown="if(event.key===\'Enter\')searchCurveLibrary()"></div><div class="field"><label>&nbsp;</label><button type="button" onclick="searchCurveLibrary()">搜索曲线库</button></div></div><div id="curveLibResults" class="acc-list"><div class="empty">输入关键词搜索公共配光曲线库，找到后确认配对到当前产品。</div></div>';
$('tab-curves').innerHTML=html
}
