  let form=$('curveUploadForm'); if(!form)return;
  try{let fd=new FormData(form);state.current=await api('upload_files',{method:'POST',body:fd});renderDetail(state.current);switchTab('curves');refreshPdf();msg('配光曲线已上传并写入当前产品PDF')}catch(e){msg(e.message,true)}
}
async function searchCurveLibrary(){
  if(!state.current)return; let kw=$('curveKw')?$('curveKw').value:'';
  try{let rows=await api('curve_library',{qs:'kw='+encodeURIComponent(kw)});let box=$('curveLibResults'); if(!rows.length){box.innerHTML='<div class="empty">没有找到配光曲线。</div>';return} box.innerHTML=rows.map(r=>'<div class="item"><b>'+esc(r.file_title||r.original_name)+'</b><small>'+esc(r.model_no||'公共库')+' ｜ '+esc(r.uploaded_at||'')+'</small><img class="mini-thumb2" src="'+esc(r.url)+'" onclick="openImagePreview(\''+esc(r.url)+'\',\'配光曲线\')"><div class="item-actions"><button onclick="openImagePreview(\''+esc(r.url)+'\',\'配光曲线\')">预览</button><button onclick="copyCurveToCurrent('+r.id+')">复制到当前产品</button>'+(state.perms.delete_file?'<button class="danger" onclick="deleteLibraryFile('+r.id+')">删除</button>':'')+'</div></div>').join('');}catch(e){msg(e.message,true)}
}
async function copyCurveToCurrent(fileId){
  if(!confirm('确认把这张配光曲线从公共库配对到当前型号 '+(state.current&&state.current.model_no||'')+'？'))return;
  try{state.current=await api('copy_file_to_product',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({file_id:fileId,naming_model_id:state.current.id,model_no:state.current.model_no,file_type:'配光曲线'})});renderDetail(state.current);switchTab('curves');refreshPdf();msg('已复制配光曲线到当前产品')}catch(e){msg(e.message,true)}
}

async function searchAccessoryImages(){if(!state.current)return;let kw=$('accFileKw')?$('accFileKw').value:'';try{let rows=await api('image_asset_library',{qs:'kind='+encodeURIComponent('配件图片')+'&kw='+encodeURIComponent(kw)});let box=$('accFileResults');if(!rows.length){box.innerHTML='<div class="empty">没有找到配件图。</div>';return}box.innerHTML=rows.map(r=>'<div class="item"><b>'+esc(r.file_title||r.original_name)+'</b><small>'+esc(r.model_no)+' ｜ '+esc(r.uploaded_at||'')+'</small><img class="mini-thumb2" src="'+esc(r.url)+'"><div class="item-actions"><button onclick="copyAccessoryImageToCurrent('+r.id+')">复制到当前产品</button></div></div>').join('')}catch(e){msg(e.message,true)}}
async function copyAccessoryImageToCurrent(fileId){if(!confirm('确认把这张配件图从公共库配对到当前型号 '+(state.current&&state.current.model_no||'')+'？'))return;try{state.current=await api('copy_file_to_product',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({file_id:fileId,naming_model_id:state.current.id,model_no:state.current.model_no,file_type:'配件图片'})});renderDetail(state.current);switchTab('acc');refreshPdf();msg('已复制配件图到当前产品')}catch(e){msg(e.message,true)}}
async function uploadNamedForm(formId,okMsg){let form=$(formId);if(!form)return;try{let fd=new FormData(form);state.current=await api('upload_files',{method:'POST',body:fd});renderDetail(state.current);refreshPdf();msg(okMsg||'已上传')}catch(e){msg(e.message,true)}}
function openQuickUpload(type){if(!state.current){msg('请先选择一个产品，再上传 '+type,true);return}$('qu_model').value=state.current.model_no;$('qu_id').value=state.current.id;$('qu_type').value=type;$('qu_title').value=type;$('qu_note').value='';$('qu_files').value='';$('quickUploadTitle').textContent='上传 '+type+' 到 '+state.current.model_no;$('quickUploadModal').classList.add('show')}
function closeQuickUpload(){$('quickUploadModal').classList.remove('show')}
async function submitQuickUpload(){try{let fd=new FormData($('quickUploadForm'));state.current=await api('upload_files',{method:'POST',body:fd});closeQuickUpload();renderDetail(state.current);if($('qu_type').value==='配件图片')switchTab('acc');else if($('qu_type').value==='配光曲线')switchTab('curves');else switchTab('files');refreshPdf();msg('已上传 '+$('qu_type').value)}catch(e){msg(e.message,true)}}


function openLibraryUpload(type){$('lu_type').value=type;$('lu_title').value=type==='配光曲线'?'':type;$('lu_model_hint').value=(type==='配光曲线'&&state.current)?(state.current.model_no||''):'';$('lu_note').value='';$('lu_files').value='';let isCurve=type==='配光曲线';if($('lu_normal_files_wrap'))$('lu_normal_files_wrap').hidden=isCurve;if($('lu_curve_slots')){$('lu_curve_slots').hidden=!isCurve;$('lu_curve_slots').querySelectorAll('[data-curve-file]').forEach(input=>{input.value=''});$('lu_curve_slots').querySelectorAll('[data-curve-preview]').forEach(box=>{box.innerHTML='预览'});bindCurveUploadPreviews()}$('libraryUploadTitle').textContent='上传到公共'+(type==='高清图片'?'高清图库':type==='配件图片'?'配件图库':'配光曲线库');$('libraryUploadModal').classList.add('show')}
function closeLibraryUpload(){$('libraryUploadModal').classList.remove('show')}
function bindCurveUploadPreviews(){document.querySelectorAll('#lu_curve_slots [data-curve-file]').forEach(input=>{if(input._bound)return;input._bound=1;input.addEventListener('change',function(){let box=input.closest('.curve-upload-slot').querySelector('[data-curve-preview]');let file=input.files&&input.files[0];if(!file){box.innerHTML='预览';return}let url=URL.createObjectURL(file);box.innerHTML='<img src="'+url+'" alt="preview">';})})}
async function submitLibraryUpload(){try{let form=$('libraryUploadForm');let fd=new FormData(form);let hint=$('lu_model_hint').value.trim();if(hint){fd.set('model_no',hint);fd.set('naming_model_id','0')}if($('lu_type').value==='配光曲线'){fd.delete('files[]');let angles=[];let added=0;document.querySelectorAll('#lu_curve_slots .curve-upload-slot').forEach(slot=>{let angle=(slot.querySelector('[data-curve-angle]').value||'').trim();let fileInput=slot.querySelector('[data-curve-file]');let file=fileInput.files&&fileInput.files[0];if(file){fd.append('files[]',file,file.name);angles.push(angle||('角度'+(added+1)));added++;}});if(!added)throw new Error('请至少选择一个角度的配光曲线图片。');fd.set('curve_angles',angles.join(','));}await api('upload_files',{method:'POST',body:fd});closeLibraryUpload();msg('已上传到公共资料库');if($('libraryManagerModal').classList.contains('show'))searchLibraryManager();}catch(e){msg(e.message,true)}}
let currentLibraryType='高清图片';
function openLibraryManager(){currentLibraryType='高清图片';$('libraryManagerModal').classList.add('show');setLibraryType('高清图片')}
function openUploadedCurves(){currentLibraryType='配光曲线';if($('libKw'))$('libKw').value=state.current?(state.current.model_no||''):'';$('libraryManagerModal').classList.add('show');setLibraryType('配光曲线')}
function closeLibraryManager(){$('libraryManagerModal').classList.remove('show')}
function setLibraryType(t){currentLibraryType=t;document.querySelectorAll('[data-lib-type]').forEach(b=>b.classList.toggle('active',b.dataset.libType===t));searchLibraryManager()}
async function searchLibraryManager(){let kw=$('libKw')?$('libKw').value:'';try{let rows=await api('image_asset_library',{qs:'kind='+encodeURIComponent(currentLibraryType)+'&kw='+encodeURIComponent(kw)});let box=$('libraryManagerResults');if(!rows.length){box.innerHTML='<div class="empty">没有找到资料。</div>';return}if(currentLibraryType==='配光曲线'){box.innerHTML='<div class="image-grid">'+rows.map(r=>'<div class="image-tile"><img src="'+esc(r.url)+'" onclick="openImagePreview(\''+esc(r.url)+'\',\'配光曲线\')"><b>'+esc(r.file_title||r.original_name)+'</b><small>'+esc(r.model_no||'公共库')+' ｜ '+esc(r.uploaded_at||'')+'</small><div class="item-actions"><button onclick="openImagePreview(\''+esc(r.url)+'\',\'配光曲线\')">预览</button>'+(state.current?'<button onclick="copyLibraryFileToCurrent('+r.id+')">配对</button>':'')+'<button onclick="editLibraryFile('+r.id+',\''+esc(r.file_title||r.original_name||'')+'\',\'配光曲线\',\''+esc(r.note||'')+'\')">修改</button>'+(state.perms.delete_file?'<button class="danger" onclick="deleteLibraryFile('+r.id+')">删除</button>':'')+'</div></div>').join('')+'</div>';return}box.innerHTML=rows.map(r=>'<div class="item"><b>'+esc(r.file_title||r.original_name)+'</b><small>'+esc(r.model_no||'公共库')+' ｜ '+esc(r.note||'')+' ｜ '+esc(r.uploaded_at||'')+'</small><img class="mini-thumb2" src="'+esc(r.url)+'" onclick="openImagePreview(\''+esc(r.url)+'\',\'资料预览\')"><div class="item-actions"><button onclick="openImagePreview(\''+esc(r.url)+'\',\'资料预览\')">预览</button>'+(state.current?'<button onclick="copyLibraryFileToCurrent('+r.id+')">配对到当前产品</button>':'')+'<button onclick="editLibraryFile('+r.id+',\''+esc(r.file_title||r.original_name||'')+'\',\''+esc(currentLibraryType)+'\',\''+esc(r.note||'')+'\')">修改</button>'+(state.perms.delete_file?'<button class="danger" onclick="deleteLibraryFile('+r.id+')">删除</button>':'')+'</div></div>').join('')}catch(e){msg(e.message,true)}}
async function copyLibraryFileToCurrent(fileId){if(!state.current){msg('请先选择一个产品，再配对。',true);return}let type=currentLibraryType==='配光曲线'?'配光曲线':(currentLibraryType==='配件图片'?'配件图片':'高清图片');if(!confirm('确认把这个'+type+'配对到当前型号 '+state.current.model_no+'？'))return;try{state.current=await api('copy_file_to_product',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({file_id:fileId,naming_model_id:state.current.id,model_no:state.current.model_no,file_type:type})});renderDetail(state.current);if(type==='配光曲线')switchTab('curves');else if(type==='配件图片')switchTab('acc');else switchTab('files');refreshPdf();msg('已配对到当前产品')}catch(e){msg(e.message,true)}}
async function deleteLibraryFile(id){if(!confirm('确认删除这个公共库图片？已配对到产品的记录不会自动消失，请谨慎。'))return;try{await api('delete_file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:id})});searchLibraryManager();msg('已删除')}catch(e){msg(e.message,true)}}
async function deleteFile(id,tab){if(!confirm('确认删除这个资料？删除后 PDF 不再显示。'))return;try{state.current=await api('delete_file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:id})});renderDetail(state.current);if(tab)switchTab(tab);refreshPdf();msg('已删除')}catch(e){msg(e.message,true)}}
async function uploadFiles(){let form=$('uploadForm');if(!form)return;try{let fd=new FormData(form);state.current=await api('upload_files',{method:'POST',body:fd});renderDetail(state.current);switchTab('files');refreshPdf();msg('资料已上传')}catch(e){msg(e.message,true)}}
async function editLibraryFile(id,title,type,note){let nextTitle=prompt('资料名称 / 角度标题：',title||'');if(nextTitle===null)return;let nextNote=prompt('说明 / 关键词：',note||'');if(nextNote===null)return;try{let data={id:id,file_title:nextTitle,file_type:type||currentLibraryType||'配光曲线',note:nextNote,visibility:'customer'};let res=await api('update_file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});if(state.current&&res&&res.model_no===state.current.model_no){state.current=res;renderDetail(state.current);refreshPdf()}if($('libraryManagerModal').classList.contains('show'))searchLibraryManager();msg('资料信息已修改')}catch(e){msg(e.message,true)}}

function renderConfig(p){['芯片','光学','电源','配件'].forEach(t=>state.configSelected[t]=(p.configs||[]).filter(c=>c.config_type===t).map(c=>c.material));let html='<div class="config-tabs"><button class="active" data-cfg="芯片" onclick="setConfigType(\'芯片\')">芯片</button><button data-cfg="光学" onclick="setConfigType(\'光学\')">光学</button><button data-cfg="电源" onclick="setConfigType(\'电源\')">电源</button><button data-cfg="配件" onclick="setConfigType(\'配件\')">配件</button></div><div class="form-grid"><div class="field span3"><label>BOM物料模糊查找</label><input id="matKw" placeholder="输入芯片/透镜/电源/蜂巢网/四叶片等关键词" onkeydown="if(event.key===\'Enter\')searchMaterials()"></div><div class="field span3"><button class="primary" onclick="searchMaterials()">搜索BOM物料</button></div></div><h3>搜索结果</h3><div id="matResults" class="mat-list"><div class="empty">输入关键词后搜索 BOM 共享物料库。</div></div><h3>当前配置</h3><div id="configChosen" class="config-list"></div><button class="primary" onclick="saveConfig()">保存当前选项卡配置</button>';$('tab-config').innerHTML=html;renderConfigChosen()}
function setConfigType(t){state.configType=t;document.querySelectorAll('#tab-config [data-cfg]').forEach(b=>b.classList.toggle('active',b.dataset.cfg===t));renderConfigChosen()}
async function searchMaterials(){let kw=$('matKw').value.trim();try{let d=await api('materials',{qs:'kw='+encodeURIComponent(kw)+'&group='+encodeURIComponent(state.configType)+'&limit=100'});let b=$('matResults');b.innerHTML='';state.matResults=d.rows||[];if(!state.matResults.length){b.innerHTML='<div class="empty">没有找到物料。</div>';return}state.matResults.forEach((m,i)=>{let div=document.createElement('div');div.className='item mat-row';div.innerHTML='<div><b>'+esc((m.brand?m.brand+' / ':'')+m.name)+'</b><small>'+esc(m.category)+' ｜ '+esc(m.model)+' ｜ '+esc(m.spec)+'<br>供应商：'+esc(m.supplier)+' ｜ 单价：'+esc(m.price)+' '+esc(m.unit)+'</small></div><button onclick="addConfigMaterialByIndex('+i+')">加入</button>';b.appendChild(div)})}catch(e){msg(e.message,true)}}
function addConfigMaterialByIndex(i){let m=(state.matResults||[])[i];if(!m)return;if(!state.configSelected[state.configType])state.configSelected[state.configType]=[];if(!state.configSelected[state.configType].some(x=>Number(x.id)===Number(m.id)))state.configSelected[state.configType].push(m);renderConfigChosen()}
function removeConfigMaterial(id){state.configSelected[state.configType]=state.configSelected[state.configType].filter(x=>Number(x.id)!==Number(id));renderConfigChosen()}
function renderConfigChosen(){let b=$('configChosen');if(!b)return;let arr=state.configSelected[state.configType]||[];b.innerHTML='';if(!arr.length){b.innerHTML='<div class="empty">当前没有选择 '+esc(state.configType)+'</div>';return}arr.forEach(m=>{let div=document.createElement('div');div.className='item';div.innerHTML='<b>'+esc((m.brand?m.brand+' / ':'')+m.name)+'</b><small>'+esc(m.model)+' ｜ '+esc(m.spec)+'</small><div class="item-actions"><button class="danger" onclick="removeConfigMaterial('+Number(m.id)+')">移除</button></div>';b.appendChild(div)})}
async function saveConfig(){try{state.current=await api('save_configs',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({naming_model_id:state.current.id,model_no:state.current.model_no,config_type:state.configType,items:state.configSelected[state.configType]||[]})});renderDetail(state.current);switchTab('config');msg('配置已保存')}catch(e){msg(e.message,true)}}
function renderRecords(rows){let snaps=(state.current&&state.current.snapshots)||[];let html='<div class="send-form form-grid"><div class="field"><label>客户名称</label><input id="customerName"></div><div class="field"><label>客户邮箱</label><input id="customerEmail"></div><div class="field"><label>发送说明 / 快照备注</label><input id="sendNote" placeholder="发了PDF/IES/高清图"></div><div class="field span3"><button class="primary" onclick="recordSend()">记录已发送资料并保存快照</button> <button onclick="createSnapshot()">只保存当前资料快照</button></div></div><h3>资料快照</h3><div class="record-list">';if(!snaps.length)html+='<div class="empty">暂无快照</div>';snaps.forEach(r=>{html+='<div class="item"><b>快照 #'+esc(r.id)+' · '+esc(r.snapshot_title||'资料快照')+'</b><small>'+esc(r.created_by)+' '+esc(r.created_at)+(r.customer_name?'<br>客户：'+esc(r.customer_name)+' '+esc(r.customer_email||''):'')+(r.send_note?'<br>'+esc(r.send_note):'')+'</small></div>'});html+='</div><h3>生成/发送记录</h3><div class="record-list">';if(!rows.length)html+='<div class="empty">暂无记录</div>';rows.forEach(r=>{html+='<div class="item"><b>'+esc(r.record_type)+' · '+esc(r.file_title||'记录')+'</b><small>'+esc(r.created_by)+' '+esc(r.created_at)+(r.snapshot_id?'<br>快照：#'+esc(r.snapshot_id):'')+(r.customer_name?'<br>客户：'+esc(r.customer_name)+' '+esc(r.customer_email||''):'')+(r.note?'<br>'+esc(r.note):'')+'</small></div>'});html+='</div>';$('tab-records').innerHTML=html}
async function recordSend(){try{state.current=await api('record_send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({naming_model_id:state.current.id,model_no:state.current.model_no,customer_name:$('customerName').value,customer_email:$('customerEmail').value,note:$('sendNote').value})});renderDetail(state.current);switchTab('records');msg('已记录发送并保存快照')}catch(e){msg(e.message,true)}}
async function createSnapshot(){try{state.current=await api('create_snapshot',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({naming_model_id:state.current.id,model_no:state.current.model_no,customer_name:$('customerName')?$('customerName').value:'',customer_email:$('customerEmail')?$('customerEmail').value:'',note:$('sendNote')?$('sendNote').value:''})});renderDetail(state.current);switchTab('records');msg('当前资料快照已保存')}catch(e){msg(e.message,true)}}
function pdfUrl(){return state.current?'datasheet_pdf.php?id='+encodeURIComponent(state.current.id)+'&model_no='+encodeURIComponent(state.current.model_no)+'&logo=0':''}function refreshPdf(){if(!state.current)return;let url='';if(Number(state.current.is_website)&&state.current.website_cache_status==='empty'){url=officialPdfUrl(state.current);}if(!url)url=pdfUrl()+'&t='+(Date.now());$('pdfFrame').src=url;savePlace()}function openPdf(){if(!state.current)return;let url=(Number(state.current.is_website)&&state.current.website_cache_status==='empty')?officialPdfUrl(state.current):'';window.open(url||pdfUrl(),'_blank')}function printPdf(){if(!$('pdfFrame').src||$('pdfFrame').src==='about:blank')return;try{$('pdfFrame').contentWindow.print()}catch(e){openPdf()}}
function openImagePreview(url,title){
  if(!url)return;
  let m=document.getElementById('imgPreviewMask');
  if(!m){
    m=document.createElement('div');
    m.id='imgPreviewMask';
    m.className='img-preview-mask';
    m.innerHTML='<div class="img-preview-box"><div class="img-preview-head"><span id="imgPreviewTitle">图片预览</span><button onclick="closeImagePreview()">关闭</button></div><div class="img-preview-img"><img id="imgPreviewImg" src=""></div></div>';
    m.addEventListener('click',function(e){if(e.target===m)closeImagePreview();});
    document.body.appendChild(m);
  }
  document.getElementById('imgPreviewTitle').textContent=title||'图片预览';
  document.getElementById('imgPreviewImg').src=url;
  m.classList.add('show');
}
function closeImagePreview(){let m=document.getElementById('imgPreviewMask');if(m)m.classList.remove('show')}

function switchTab(id){document.querySelectorAll('.tab').forEach(x=>x.classList.toggle('active',x.dataset.tab===id));document.querySelectorAll('.tab-body').forEach(x=>x.classList.toggle('active',x.id==='tab-'+id));if(id==='acc'&&state.current&&!state.accessoryLib)loadAccessoryLib();if((id==='files'||id==='records'||id==='config'||id==='curves')&&state.current&&!(state.current._relatedLoaded)){loadRelated(state.current.id,true);state.current._relatedLoaded=true}}
function batchPdf(){let ids=needSelected();if(ids)location.href='datasheet_package.php?mode=batch_pdf&ids='+ids.join(',')}function batchZip(pack){let ids=needSelected();if(ids)location.href='datasheet_package.php?mode=package&pack='+encodeURIComponent(pack)+'&ids='+ids.join(',')}function batchExcel(){let ids=needSelected();if(ids)location.href='datasheet_excel.php?ids='+ids.join(',')}
function openAccessoryManager(){state.accType='配件';$('a_type').value='配件';$('accModal').classList.add('show');loadAccManager()}function closeAccessoryManager(){$('accModal').classList.remove('show')}function setAccType(t){state.accType=t;$('a_type').value=t;document.querySelectorAll('[data-am]').forEach(x=>x.classList.toggle('active',x.dataset.am===t));loadAccManager()}async function loadAccManager(){try{let rows=await api('accessories',{qs:'type='+encodeURIComponent(state.accType)});let b=$('accessoryManagerList');b.innerHTML='';if(!rows.length){b.innerHTML='<div class="empty">暂无 '+esc(state.accType)+'</div>';return}rows.forEach(a=>{let div=document.createElement('div');div.className='item';div.innerHTML='<b>'+esc(a.model_no? a.model_no+' · '+(a.name_en||a.name_cn):(a.name_en||a.name_cn))+'</b><small>'+esc(a.accessory_type)+' ｜ '+esc(a.brand)+' ｜ '+esc(a.category)+'</small><div class="item-actions"><button class="danger" onclick="deleteAccessory('+a.id+')">停用</button></div>';b.appendChild(div)})}catch(e){msg(e.message,true)}}async function saveAccessory(){try{let fd=new FormData();['type','category','brand','name_cn','name_en','model'].forEach(k=>{});fd.append('accessory_type',$('a_type').value);fd.append('category',$('a_category').value);fd.append('brand',$('a_brand').value);fd.append('name_cn',$('a_name_cn').value);fd.append('name_en',$('a_name_en').value);fd.append('model_no',$('a_model').value);fd.append('description',$('a_desc').value);if($('a_img').files[0])fd.append('image_file',$('a_img').files[0]);await api('save_accessory',{method:'POST',body:fd});msg('已保存到库');loadAccManager();if(state.current)renderAccessories(state.current)}catch(e){msg(e.message,true)}}async function deleteAccessory(id){if(!confirm('停用这个配件/配置？'))return;try{await api('delete_accessory',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id})});loadAccManager();msg('已停用')}catch(e){msg(e.message,true)}}async function materialToAccessory(){let kw=prompt('输入BOM物料关键词：',state.accType);if(kw===null)return;try{let d=await api('materials',{qs:'kw='+encodeURIComponent(kw)+'&group='+encodeURIComponent(state.accType)+'&limit=20'});if(!d.rows.length){msg('没有找到物料',true);return}let m=d.rows[0];await api('import_material_accessory',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({accessory_type:state.accType,material:m})});msg('已从BOM导入：'+m.name);loadAccManager()}catch(e){msg(e.message,true)}}
let permSelected=null;async function openPerms(){try{let d=await api('permissions_list');state.permData=d;$('permModal').classList.add('show');renderPermUsers()}catch(e){msg(e.message,true)}}function closePerms(){$('permModal').classList.remove('show')}function renderPermUsers(){let q=($('permSearch').value||'').toLowerCase();let b=$('permUsers');b.innerHTML='';(state.permData.users||[]).filter(u=>!q||[u.username,u.display_name,u.department].join(' ').toLowerCase().includes(q)).forEach(u=>{let div=document.createElement('div');div.className='user-row '+(permSelected&&permSelected.id===u.id?'active':'');div.onclick=()=>{permSelected=u;renderPermUsers();renderPermFeatures()};div.innerHTML='<b>'+esc(u.display_name||u.username)+'</b><br><small>'+esc(u.username)+' ｜ '+esc(u.department||'')+'</small>';b.appendChild(div)});if(!permSelected&&state.permData.users&&state.permData.users[0]){permSelected=state.permData.users[0];renderPermFeatures()}}function renderPermFeatures(){if(!permSelected)return;$('permTitle').textContent=(permSelected.display_name||permSelected.username)+' 的资料权限';let b=$('permFeatures');b.innerHTML='';Object.entries(state.permData.features||{}).forEach(([k,d])=>{let div=document.createElement('label');div.className='feature';div.innerHTML='<input type="checkbox" data-f="'+esc(k)+'" '+(permSelected.features&&permSelected.features[k]?'checked':'')+'>'+esc(d.label)+'<br><small>'+esc(d.group||'')+'</small>';b.appendChild(div)})}async function savePerms(){if(!permSelected)return;let features={};document.querySelectorAll('#permFeatures input').forEach(x=>features[x.dataset.f]=x.checked?1:0);try{await api('permissions_save',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:permSelected.id,features})});msg('权限已保存');openPerms()}catch(e){msg(e.message,true)}}

// V2.1.5 PRO override functions
let onlineTimer=null;
function setSettingsTab(tab){document.querySelectorAll('[data-set-tab]').forEach(x=>x.classList.toggle('active',x.dataset.setTab===tab));document.querySelectorAll('.set-tab').forEach(x=>x.style.display=(x.id==='setTab-'+tab)?'block':'none');}
function previewSettings(){if($('settingsPreviewTitle'))$('settingsPreviewTitle').textContent=$('setTitle')?$('setTitle').value:'资料生成系统';if($('settingsPreviewSub'))$('settingsPreviewSub').textContent=$('setSubtitle')?$('setSubtitle').value:'Datasheet Center';if($('settingsPreviewCompany'))$('settingsPreviewCompany').textContent=$('setCompany')?$('setCompany').value:'Artdon Lighting Limited';}
function fillSettingsForm(){let s=dsSettings||{},ui=s.ui||{},h=s.header||{},w=s.watermark||{};$('setFontScale').value=ui.font_scale||'.88';$('setTheme').value=ui.theme||'blue';if($('setListDensity'))$('setListDensity').value=ui.list_density||'compact';if($('setHomeView'))$('setHomeView').value=ui.home_view||'pro';if($('setShowOnlineTop'))$('setShowOnlineTop').value=String(ui.show_online_top??1);$('setPdfHeight').value=ui.pdf_height||820;$('setCatWidth').value=ui.cat_card_width||190;$('setListWidth').value=ui.product_list_width||360;$('setDetailWidth').value=ui.detail_width||520;$('setPdfWidth').value=ui.pdf_width||720;$('setTitle').value=h.title||'资料生成系统';$('setSubtitle').value=h.subtitle||'';$('setCompany').value=h.company||'Artdon Lighting Limited';if($('setCustomHeaderHtml'))$('setCustomHeaderHtml').value=h.custom_header_html||'';$('setPdfHeaderEnabled').value=String(h.pdf_header_enabled||0);$('setPdfHeaderTitle').value=h.pdf_header_title||h.company||'Artdon Lighting Limited';$('setPdfHeaderSubtitle').value=h.pdf_header_subtitle||'Architectural Lighting Datasheet';$('setPdfFooterText').value=h.pdf_footer_text||h.company||'Artdon Lighting Limited';$('setWatermarkText').value=w.text||'';$('setWatermarkEnabled').value=String(w.enabled||0);$('setWatermarkOpacity').value=w.opacity||.08;$('setCategoryOrder').value=(s.category_order||[]).join('\n');renderCategoryOrderEditor(s.category_order&&s.category_order.length?s.category_order:currentCategoryNames());previewSettings();}
function readSettingsForm(){syncCategoryOrderTextarea();return {ui:{font_scale:$('setFontScale').value,theme:$('setTheme').value,pdf_height:$('setPdfHeight').value,cat_card_width:$('setCatWidth').value,product_list_width:$('setListWidth').value,detail_width:$('setDetailWidth').value,pdf_width:$('setPdfWidth').value,list_density:$('setListDensity')?$('setListDensity').value:'compact',home_view:$('setHomeView')?$('setHomeView').value:'pro',show_online_top:$('setShowOnlineTop')?$('setShowOnlineTop').value:'1'},header:{title:$('setTitle').value,subtitle:$('setSubtitle').value,company:$('setCompany').value,custom_header_html:$('setCustomHeaderHtml')?$('setCustomHeaderHtml').value:'',custom_header_enabled:'1',pdf_header_enabled:$('setPdfHeaderEnabled').value,pdf_header_title:$('setPdfHeaderTitle').value,pdf_header_subtitle:$('setPdfHeaderSubtitle').value,pdf_footer_text:$('setPdfFooterText').value},watermark:{text:$('setWatermarkText').value,enabled:Number($('setWatermarkEnabled').value),opacity:$('setWatermarkOpacity').value},category_order:$('setCategoryOrder').value}}
function openSettings(){fillSettingsForm();setSettingsTab('ui');$('settingsModal').classList.add('show')}
function updateTopUser(b){try{let u=b.user||{},on=b.online||[];if($('topUserName'))$('topUserName').textContent=(u.display_name||u.name||u.username||'当前用户');if($('topOnlineCount'))$('topOnlineCount').textContent=on.length||0;if($('topOnlineStatus'))$('topOnlineStatus').style.display=String((b.settings&&b.settings.ui&&b.settings.ui.show_online_top)??1)==='0'?'none':'flex';}catch(e){}}
async function boot(){try{let b=await api('bootstrap');state.perms=b.perms||{};dsSettings=b.settings||{};applySettings(dsSettings);updateTopUser(b);$('stProducts').textContent=b.stats.products||0;$('stFiles').textContent=b.stats.files||0;$('stRecords').textContent=b.stats.records||0;$('stAcc').textContent=b.stats.accessories||0;let old=loadPlace();if(old.kw)$('kw').value=old.kw;if(old.item)$('itemFilter').value=old.item;if(old.source)$('sourceFilter').value=old.source;if(old.per)$('perPage').value=old.per;state.activeCat=old.cat||'';let h=await api('home');if(h.online)updateTopUser({online:h.online,user:b.user,settings:b.settings});state.cats=h.categories||[];sortCatsBySettings();renderCats();await loadProducts(old.page||1);if(old.id){setTimeout(()=>selectProduct(old.id),120)}}catch(e){msg(e.message,true)}}
function openOnlineCenter(){$('onlineModal').classList.add('show');loadOnlineList();clearInterval(onlineTimer);onlineTimer=setInterval(loadOnlineList,30000)}
function closeOnlineCenter(){$('onlineModal').classList.remove('show');clearInterval(onlineTimer)}

function openStorageCenter(){$('storageModal').classList.add('show');loadStorageOverview()}
function closeStorageCenter(){$('storageModal').classList.remove('show')}
async function loadStorageOverview(){try{let d=await api('storage_overview');let s=d.summary||{};$('storTotal').textContent=s.total_known_text||'0 B';$('storUpload').textContent=s.upload_text||'0 B';$('storLogs').textContent=(s.log_text||'0 B')+' / '+(s.log_rows||0)+'条';$('storSnaps').textContent=(s.snapshot_text||'0 B')+' / '+(s.snapshot_rows||0)+'条';let max=1;(d.groups||[]).forEach(g=>{max=Math.max(max,Number(g.bytes||0))});let gh='';(d.groups||[]).forEach(g=>{let pct=Math.max(2,Math.round(Number(g.bytes||0)*100/max));gh+='<div class="storage-row"><div class="line"><span>'+esc(g.name)+' · '+(g.count||0)+'个</span><b>'+esc(g.text||'0 B')+'</b></div><div class="bar"><i style="width:'+pct+'%"></i></div></div>'});$('storageGroups').innerHTML=gh||'<div class="empty">暂无上传资料</div>';let th='';Object.values(d.tables||{}).forEach(t=>{let pct=Math.max(2,Math.round(Number(t.bytes||0)*100/Math.max(1,...Object.values(d.tables||{}).map(x=>Number(x.bytes||0)))));th+='<div class="storage-row"><div class="line"><span>'+esc(t.table)+' · '+(t.rows||0)+'行</span><b>'+esc(t.text||'0 B')+'</b></div><div class="bar"><i style="width:'+pct+'%"></i></div></div>'});$('storageTables').innerHTML=th;let wh=(d.warnings||[]).map(w=>'<div class="storage-tip">'+esc(w)+'</div>').join('');$('storageWarnings').innerHTML=wh;let rh='<table class="storage-table"><thead><tr><th>类型</th><th>文件</th><th>型号/来源</th><th>大小</th><th>上传人/时间</th></tr></thead><tbody>';(d.recent||[]).forEach(r=>{rh+='<tr><td>'+esc(r.file_type||'')+'</td><td><b>'+esc(r.file_title||r.original_name||'')+'</b><br><small>'+esc(r.original_name||'')+'</small></td><td>'+esc(r.model_no||'公共库')+'</td><td>'+esc(r.text||'')+'</td><td>'+esc(r.uploaded_by||'')+'<br><small>'+esc(r.uploaded_at||'')+'</small></td></tr>'});rh+='</tbody></table>';$('storageRecent').innerHTML=rh;if($('settingsStorageInline')){$('settingsStorageInline').innerHTML='<div class="storage-dashboard"><div class="storage-stat"><b>'+esc(s.total_known_text||'0 B')+'</b><span>合计</span></div><div class="storage-stat"><b>'+esc(s.upload_text||'0 B')+'</b><span>上传目录</span></div><div class="storage-stat"><b>'+esc(s.log_text||'0 B')+'</b><span>日志</span></div><div class="storage-stat"><b>'+esc(s.snapshot_text||'0 B')+'</b><span>快照</span></div></div>'}}catch(e){msg(e.message,true)}}
async function loadOnlineList(){try{let d=await api('online_list');let rows=d.online||[];if($('onlineTotal'))$('onlineTotal').textContent=rows.length;if($('onlineActive5'))$('onlineActive5').textContent=rows.filter(r=>Number(r.idle_minutes||0)<=5).length;if($('onlineCurrentUser'))$('onlineCurrentUser').textContent=($('topUserName')&&$('topUserName').textContent)||'-';if($('onlineLastRefresh'))$('onlineLastRefresh').textContent=new Date().toLocaleTimeString();if($('topOnlineCount'))$('topOnlineCount').textContent=rows.length;let html='<table class="online-table"><thead><tr><th>状态</th><th>人员</th><th>部门/角色</th><th>最后动作</th><th>IP</th><th>最后在线</th></tr></thead><tbody>';if(!rows.length)html+='<tr><td colspan="6">暂无在线人员</td></tr>';rows.forEach(r=>{html+='<tr><td><span class="status-pill">在线</span></td><td><b>'+esc(r.display_name||r.username)+'</b><br><small>'+esc(r.username||'')+'</small></td><td>'+esc(r.department||'-')+'<br><small>'+esc(r.role_name||'')+'</small></td><td>'+esc(r.module_name||'资料生成系统')+'<br><small>'+esc(r.page_title||'')+'</small></td><td>'+esc(r.ip||'')+'</td><td>'+esc(r.last_seen||'')+'<br><small>'+esc(r.idle_minutes||0)+' 分钟前</small></td></tr>'});html+='</tbody></table>';$('onlineCenterList').innerHTML=html}catch(e){msg(e.message,true)}}
async function loadLogs(){try{let q=new URLSearchParams();if($('logKw')&&$('logKw').value.trim())q.set('kw',$('logKw').value.trim());if($('logUser')&&$('logUser').value.trim())q.set('user',$('logUser').value.trim());if($('logModel')&&$('logModel').value.trim())q.set('model_no',$('logModel').value.trim());if($('logAction')&&$('logAction').value)q.set('action_type',$('logAction').value);if($('logSection')&&$('logSection').value.trim())q.set('section',$('logSection').value.trim());if($('logSource')&&$('logSource').value)q.set('source_type',$('logSource').value);if($('logFileType')&&$('logFileType').value.trim())q.set('file_type',$('logFileType').value.trim());if($('logDateFrom')&&$('logDateFrom').value)q.set('date_from',$('logDateFrom').value);if($('logDateTo')&&$('logDateTo').value)q.set('date_to',$('logDateTo').value);q.set('per_page','200');let d=await api('logs',{qs:q.toString()});let rows=d.rows||[];let b=$('logCenterList');if(!rows.length){b.innerHTML='<div class="empty">没有符合条件的日志。</div>';return}let html='<table class="log-table"><thead><tr><th>结果</th><th>动作</th><th>人员</th><th>产品/对象</th><th>版块/来源</th><th>时间/IP</th></tr></thead><tbody>';rows.forEach(r=>{html+='<tr><td><span class="status-pill '+(r.result==='error'?'err':'')+'">'+esc(r.result||'success')+'</span></td><td><b>'+esc(r.action_label||r.action)+'</b><br><small>'+esc(r.action||'')+'</small></td><td>'+esc(r.display_name||r.username||'-')+'<br><small>'+esc(r.username||'')+'</small></td><td>'+esc(r.model_no||'')+'<br><small>'+esc(r.target_title||r.target_type||'')+'</small></td><td>'+esc(r.section_name||'')+'<br><small>'+esc(r.source_type||'')+' '+esc(r.file_type||'')+(r.quantity?(' × '+esc(r.quantity)):'')+'</small><br><small>'+esc(r.source_url||'')+'</small></td><td>'+esc(r.created_at||'')+'<br><small>'+esc(r.ip||'')+'</small></td></tr>'});html+='</tbody></table>';b.innerHTML=html}catch(e){msg(e.message,true)}}
async function loadAllSnapshots(){try{let q=new URLSearchParams();if($('snapKw')&&$('snapKw').value.trim())q.set('kw',$('snapKw').value.trim());if($('snapModel')&&$('snapModel').value.trim())q.set('model_no',$('snapModel').value.trim());let d=await api('snapshots_all',{qs:q.toString()});let rows=d.rows||[];if($('snapCustomer')&&$('snapCustomer').value.trim()){let ck=$('snapCustomer').value.trim().toLowerCase();rows=rows.filter(r=>String(r.customer_name||'').toLowerCase().includes(ck)||String(r.customer_email||'').toLowerCase().includes(ck));}let b=$('snapshotList');b.innerHTML='';if(!rows.length){b.innerHTML='<div class="empty">没有快照。</div>';return}rows.forEach(r=>{let div=document.createElement('div');div.className='item';div.onclick=()=>loadSnapshotDetail(r.id);div.innerHTML='<b>#'+esc(r.id)+' · '+esc(r.model_no)+'</b><small>客户：'+esc(r.customer_name||'未填写')+' '+esc(r.customer_email||'')+'<br>保存：'+esc(r.created_by)+' '+esc(r.created_at)+'<br>'+esc(r.send_note||'')+'</small>';b.appendChild(div)})}catch(e){msg(e.message,true)}}

boot();
</script></body></html>
